mapper.select:
SELECT o.na_org AS name, COALESCE(l.cnt, 0) AS value FROM c_ai_org o LEFT JOIN ( SELECT id_org, COUNT(1) AS cnt FROM c_ai_feature_event WHERE fg_active = '1' AND LOWER(event_status) = 'success'
AND id_region = #{query.idRegion}
GROUP BY id_org ) l ON o.id_org = l.id_org WHERE o.fg_active = '1'
AND o.id_region = #{query.idRegion}
ORDER BY value DESC
